// Prism Tunnel — osc diff'd with rotated copy, feedback creates tunnel depth
speed = 0.6

AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// osc diff'd with rotated/offset copy for geometric edges
osc(15, 0.05, 2.5)
  .diff(osc(15, 0.06, 1.5).rotate(() => time * 0.06).scrollX(0.2))
  .color(
    () => 0.5 + low() * 1.0,
    () => 0.4 + mid() * 1.0,
    () => 0.7 + high() * 0.8
  )
  .modulate(noise(2, 0.15), 0.05)
  .add(osc(8, 0.04, 3.0).color(0.2, 0.1, 0.25), 0.2)
  // feedback with rotation = tunnel depth effect
  .blend(src(o0).rotate(() => Math.sin(time * 0.05) * 0.006).hue(() => 0.004 + amp() * 0.008), 0.82)
  .saturate(() => 1.2 + low() * 0.5)
  .colorama(() => 0.003 + amp() * 0.006)
  .contrast(() => 1.03 + low() * 0.1)
  .brightness(() => 0.03 + low() * 0.03)
  .out(o0)
